/**
 * semantic-search.js
 *
 * Browser-side semantic search for damilola-oladele.dev.
 * Loads bge-small-en-v1.5 via Transformers.js (WebAssembly), fetches the
 * pre-built semantic-index.json generated by scripts/generate_embeddings.py,
 * and ranks posts by cosine similarity to the user's query.
 *
 * Activated only when the user switches the toggle in topbar.html.
 * Simple Jekyll Search (keyword mode) is unaffected.
 *
 * Index entry shape (produced by generate_embeddings.py):
 *   { title, url, tags, date, embedding }
 *   - tags: space-separated string  e.g. "open-source documentation"
 *   - date: ISO date string         e.g. "2024-11-11" or "2024-11-11 00:00:00"
 *   - embedding: number[]           384-dimensional, L2-normalised
 */

const SemanticSearch = (() => {
  // ── State ────────────────────────────────────────────────────────────────────

  let extractor   = null;   // Transformers.js feature-extraction pipeline
  let index       = null;   // Parsed semantic-index.json array
  let isReady     = false;
  let isLoading   = false;
  let activeQuery = '';     // Latest query; used to discard stale results

  // ── Constants ─────────────────────────────────────────────────────────────────

  const MODEL_ID  = 'Xenova/bge-small-en-v1.5';
  const INDEX_URL = '/assets/js/data/semantic-index.json';
  const TOP_K     = 5;

  // ── Helpers ───────────────────────────────────────────────────────────────────

  // Dot product on L2-normalised vectors == cosine similarity
  function dotProduct(a, b) {
    let sum = 0;
    for (let i = 0; i < a.length; i++) sum += a[i] * b[i];
    return sum;
  }

  function escapeHtml(str) {
    return String(str ?? '')
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#039;');
  }

  /**
   * Format the date value coming from python-frontmatter.
   * It may arrive as a full ISO datetime ("2024-11-11 00:00:00") or
   * already as a plain date string ("2024-11-11"). We always show
   * just the YYYY-MM-DD portion.
   */
  function formatDate(dateStr) {
    if (!dateStr) return '';
    return String(dateStr).slice(0, 10);
  }

  /**
   * Convert the space-separated tags string from the index into individual
   * pill-style spans, matching the visual style used elsewhere on the site.
   */
  function renderTagsHtml(tagsStr) {
    if (!tagsStr) return '';
    const tags = tagsStr.split(' ').filter(Boolean);
    const pills = tags
      .map(t => `<span class="me-1">${escapeHtml(t)}</span>`)
      .join('');
    return `<div><i class="fa fa-tag fa-fw"></i>${pills}</div>`;
  }

  // ── DOM helpers ───────────────────────────────────────────────────────────────

  function getResultsContainer() { return document.getElementById('search-results'); }
  function getStatusEl()          { return document.getElementById('semantic-search-status'); }

  function setStatus(message) {
    const el = getStatusEl();
    if (!el) return;
    el.textContent = message;
    el.style.display = message ? 'block' : 'none';
  }

  /**
   * Write a placeholder message into #search-results immediately.
   * This prevents SimpleJekyllSearch from filling the container with its own
   * "Oops! No results found." message while the semantic search is still
   * computing — SJS fires synchronously on input, but our embedding is async.
   */
  function setPlaceholder(message) {
    const container = getResultsContainer();
    if (!container) return;
    container.innerHTML = `<p class="mt-5 text-muted fst-italic">${escapeHtml(message)}</p>`;
  }

  // ── Result rendering ──────────────────────────────────────────────────────────

  function renderResults(results, query) {
    const container = getResultsContainer();
    if (!container) return;

    container.innerHTML = '';

    if (results.length === 0) {
      container.innerHTML = `
        <p class="mt-5">
          No semantic matches found for <em>${escapeHtml(query)}</em>.<br>
          <span class="text-muted">Try rephrasing as a concept or question,
          e.g. <em>"challenges in open source documentation"</em>.</span>
        </p>`;
      return;
    }

    results.forEach(({ title, url, tags, date }) => {
      const article = document.createElement('article');
      article.className = 'px-1 px-sm-2 px-lg-4 px-xl-0';

      const dateStr = formatDate(date);
      const dateHtml = dateStr
        ? `<div class="me-sm-4"><i class="far fa-calendar fa-fw"></i>${escapeHtml(dateStr)}</div>`
        : '';

      article.innerHTML = `
        <header>
          <h2><a href="${escapeHtml(url)}">${escapeHtml(title)}</a></h2>
          <div class="post-meta d-flex flex-column flex-sm-row text-muted mt-1 mb-1">
            ${dateHtml}
            ${renderTagsHtml(tags)}
          </div>
        </header>
        <p><em>Semantic match</em></p>
      `;

      container.appendChild(article);
    });
  }

  // ── Init: load model + index in parallel ──────────────────────────────────────

  async function init() {
    if (isReady || isLoading) return;
    isLoading = true;
    setStatus('Loading semantic search model…');

    try {
      const { pipeline } = await import(
        'https://cdn.jsdelivr.net/npm/@xenova/transformers@2/dist/transformers.min.js'
      );

      const [pipe, indexData] = await Promise.all([
        pipeline('feature-extraction', MODEL_ID, { quantized: true }),
        fetch(INDEX_URL).then(r => {
          if (!r.ok) throw new Error(`Failed to fetch semantic index: ${r.status}`);
          return r.json();
        }),
      ]);

      extractor = pipe;
      index     = indexData;
      isReady   = true;
      isLoading = false;
      setStatus('');

      // A query may have been typed while loading — run it now
      if (activeQuery) await search(activeQuery);

    } catch (err) {
      isLoading = false;
      setStatus('Semantic search failed to load. Please try keyword search.');
      console.error('[SemanticSearch] init error:', err);
    }
  }

  // ── Search ────────────────────────────────────────────────────────────────────

  async function search(query) {
    const trimmed = query.trim();
    activeQuery = trimmed;

    if (!trimmed) {
      const container = getResultsContainer();
      if (container) container.innerHTML = '';
      return;
    }

    if (!isReady) {
      // Show a waiting message in the results container immediately so
      // SimpleJekyllSearch's "Oops! No results found." never gets a chance
      // to appear while the model is still loading.
      setPlaceholder('Setting up semantic search for the first time. Your results will appear shortly. Subsequent searches are faster unless  browser cache is cleared.');
      if (!isLoading) init();
      setStatus('Loading semantic search model…');
      return;
    }

    // Model is ready. Write a placeholder before the async embedding starts
    // so the container is never empty long enough for SJS to claim it.
    setPlaceholder('Searching by meaning, please wait…');
    setStatus('Searching…');

    try {
      const output = await extractor(trimmed, { pooling: 'mean', normalize: true });
      const queryVec = Array.from(output.data);   // Float32Array → plain Array

      // Discard if a newer query arrived while we were awaiting
      if (trimmed !== activeQuery) return;

      const scored = index
        .map(post => ({ ...post, score: dotProduct(queryVec, post.embedding) }))
        .sort((a, b) => b.score - a.score)
        .slice(0, TOP_K);

      setStatus('');
      renderResults(scored, trimmed);

    } catch (err) {
      setStatus('Search error. Please try again.');
      console.error('[SemanticSearch] search error:', err);
    }
  }

  // ── Public API ────────────────────────────────────────────────────────────────

  return { init, search };
})();

export default SemanticSearch;
